import React, { useState, useEffect } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { Users, MessageSquare, Heart, TrendingUp } from 'lucide-react';
import './css/Dashboard.css';

const Dashboard = () => {
    const [activityData, setActivityData] = useState([]);
    const [stats, setStats] = useState({
        totalUsers: 0,
        totalPosts: 0,
        totalLikes: 0,
        activeUsers: 0,
    });

    useEffect(() => {
        // Simulated data fetching
        const fetchData = () => {
            // This would be replaced with actual API calls
            setActivityData([
                { name: 'Mon', posts: 4, comments: 3, likes: 7 },
                { name: 'Tue', posts: 3, comments: 5, likes: 5 },
                { name: 'Wed', posts: 2, comments: 4, likes: 3 },
                { name: 'Thu', posts: 5, comments: 2, likes: 6 },
                { name: 'Fri', posts: 4, comments: 3, likes: 4 },
                { name: 'Sat', posts: 3, comments: 2, likes: 5 },
                { name: 'Sun', posts: 2, comments: 4, likes: 3 },
            ]);

            setStats({
                totalUsers: 1234,
                totalPosts: 5678,
                totalLikes: 9876,
                activeUsers: 567,
            });
        };

        fetchData();
    }, []);

    return (
        <div className="dashboard">
            <h1>Dashboard</h1>
            <div className="stats-grid">
                <div className="stat-card">
                    <Users size={24} />
                    <h3>Total Users</h3>
                    <p>{stats.totalUsers}</p>
                </div>
                <div className="stat-card">
                    <MessageSquare size={24} />
                    <h3>Total Posts</h3>
                    <p>{stats.totalPosts}</p>
                </div>
                <div className="stat-card">
                    <Heart size={24} />
                    <h3>Total Likes</h3>
                    <p>{stats.totalLikes}</p>
                </div>
                <div className="stat-card">
                    <TrendingUp size={24} />
                    <h3>Active Users</h3>
                    <p>{stats.activeUsers}</p>
                </div>
            </div>
            <div className="chart-container">
                <h2>Weekly Activity</h2>
                <ResponsiveContainer width="100%" height={300}>
                    <BarChart data={activityData}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis dataKey="name" />
                        <YAxis />
                        <Tooltip />
                        <Legend />
                        <Bar dataKey="posts" fill="#8884d8" />
                        <Bar dataKey="comments" fill="#82ca9d" />
                        <Bar dataKey="likes" fill="#ffc658" />
                    </BarChart>
                </ResponsiveContainer>
            </div>
        </div>
    );
};

export default Dashboard;
